    def solve(self, nums: list[int]) -> bool:
        maxPage = -1
        stapled = 0
        freq = {}
        for num in nums:
            freq[num] = freq.get(num, 0) + 1
        nums.sort(reverse=True)
        for num in nums:
            if num > maxPage:
                maxPage = num
                stapled += num * freq[num]
        return stapled;

solutions.cpp:
class Solution {
public:
bool solve(vector<int>& nums) {
    int maxPage = -1;
    int stapled = 0;
    int freq[10001] = {0};
    for (int i = 0; i < nums.size(); i++) {
        freq[nums[i]]++;
    }
    sort(nums.begin(), nums.end(), greater<int>());
    for (int i = 0; i < nums.size(); i++) {
        if (nums[i] > maxPage) {
            maxPage = nums[i];
            stapled += nums[i] * freq[nums[i]];
        }
    }
    return stapled;
};
